app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password, action } = req.body;

  if (!client_id || !clients[client_id]) {
    return res.status(400).send('Invalid client_id');
  }

  const client = clients[client_id];

  if (!redirect_uri || !client.redirectUris.includes(redirect_uri)) {
    return res.status(400).send('Invalid redirect_uri');
  }

  if (action === 'deny') {
    const params = querystring.stringify({
      error: 'access_denied',
      error_description: 'User denied the request',
      state: state || ''
    });
    return res.redirect(`${redirect_uri}?${params}`);
  }

  if (!users[username] || users[username].password !== password) {
    return res.status(401).send('Invalid credentials');
  }

  const user = users[username];
  const code = generateRandomString();
  
  authorizationCodes.set(code, {
    clientId: client_id,
    redirectUri: redirect_uri,
    userId: user.userId,
    username: user.username,
    scope: scope || '',
    expiresAt: Date.now() + 600000
  });

  setTimeout(() => {
    authorizationCodes.delete(code);
  }, 600000);

  const params = querystring.stringify({
    code: code,
    state: state || ''
  });

  res.redirect(`${redirect_uri}?${params}`);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code grant type is supported'
    });
  }

  if (!client_id || !client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  const client = clients[client_id];
  if (!client || client.clientSecret !== client_secret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  if (!code || !authorizationCodes.has(code)) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  const authCode = authorizationCodes.get(code);

  if (authCode.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code expired'
    });
  }

  if (authCode.clientId !== client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was issued to another client'
    });
  }

  if (authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Redirect URI mismatch'
    });
  }

  authorizationCodes.delete(code);

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();

  accessTokens.set(accessToken, {
    clientId: client_id,
    userId: authCode.userId,
    username: authCode.username,
    scope: authCode.scope,
    expiresAt: Date.now() + 3600000
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or invalid authorization header' });
  }

  const token = authHeader.substring(7);

  if (!accessTokens.has(token)) {
    return res.status(401).json({ error: 'Invalid access token' });
  }

  const tokenData = accessTokens.get(token);

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'Access token expired' });
  }

  res.json({
    userId: tokenData.userId,
    username: tokenData.username,
    scope: tokenData.scope
  });
});

